+func resolveNamespace(cliNamespace, documentNamespace string) (string, error) {
+	if cliNamespace != "" && documentNamespace != "" && cliNamespace != documentNamespace {
+		return "", fmt.Errorf("namespace mismatch: CLI namespace %q does not match document namespace %q", cliNamespace, documentNamespace)
+	}
+
+	switch {
+	case cliNamespace != "":
+		return cliNamespace, nil
+	case documentNamespace != "":
+		return documentNamespace, nil
+	default:
+		return DefaultNamespace, nil
+	}
+}
